{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"\\d clinical_info\" | head -100",
  "description": "Inspect clinical_info schema"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"\\d clinical_info\" | tail -50",
  "description": "Inspect clinical_info schema bottom"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT column_name FROM information_schema.columns WHERE table_name = 'clinical_info' AND (column_name ILIKE '%gender%' OR column_name ILIKE '%sex%' OR column_name ILIKE '%acronym%' OR column_name ILIKE '%bcr%' OR column_name ILIKE '%barcode%' OR column_name ILIKE '%cancer%type%');\"",
  "description": "Find relevant columns"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT column_name FROM information_schema.columns WHERE table_name = 'clinical_info' ORDER BY column_name;\" | head -200",
  "description": "List all columns in clinical_info"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT \\\"Patient_description\\\" FROM clinical_info LIMIT 5;\"",
  "description": "Check Patient_description format"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT patient_id, \\\"Patient_description\\\" FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%breast%' LIMIT 5;\"",
  "description": "Find BRCA (breast) patients"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT COUNT(*) FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%Breast invasive carcinoma%' AND \\\"Patient_description\\\" ILIKE '%FEMALE%';\"",
  "description": "Count female BRCA patients"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT histological_type, COUNT(*) FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%Breast invasive carcinoma%' AND \\\"Patient_description\\\" ILIKE '%FEMALE%' GROUP BY histological_type ORDER BY COUNT(*) DESC;\"",
  "description": "Histological types in female BRCA"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' -readonly \"SELECT COUNT(DISTINCT ParticipantBarcode) FROM Mutation_Data WHERE Hugo_Symbol='CDH1' AND FILTER='PASS';\"",
  "description": "Count distinct patients with CDH1 PASS mutations"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' -readonly \"SELECT DISTINCT ParticipantBarcode FROM Mutation_Data WHERE Hugo_Symbol='CDH1' AND FILTER='PASS' LIMIT 5;\"",
  "description": "Check barcode format"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"SELECT SUBSTRING(\\\"Patient_description\\\" FROM 'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}') AS barcode, histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%Breast invasive carcinoma%' AND \\\"Patient_description\\\" ILIKE '%FEMALE%' LIMIT 5;\"",
  "description": "Extract full barcode"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d pancancer_clinical -c \"COPY (SELECT SUBSTRING(\\\"Patient_description\\\" FROM 'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}') AS barcode, histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%Breast invasive carcinoma%' AND \\\"Patient_description\\\" ILIKE '%FEMALE%' AND histological_type IS NOT NULL AND histological_type != '') TO STDOUT WITH CSV HEADER;\" > /tmp/brca_female.csv\nwc -l /tmp/brca_female.csv\nhead -3 /tmp/brca_female.csv",
  "description": "Export BRCA female clinical data"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' -readonly -csv \"SELECT DISTINCT ParticipantBarcode FROM Mutation_Data WHERE Hugo_Symbol='CDH1' AND FILTER='PASS';\" > /tmp/cdh1_mut.csv\nwc -l /tmp/cdh1_mut.csv",
  "description": "Export CDH1 mutation patients"
}
